   308		conf config.AllProvider, fim *hugofs.FileMeta, sitesMatrixBase sitesmatrix.VectorIterator, sitesMatrixBaseOnly bool,
   309	) error {
   310		// First apply the cascades with no site filtering.
   311		for cascade := range cascades.All() {
   312			if cascade.Target.SitesMatrixCompiled != nil {
   313				continue
   314			}
   315	
   316			if !cascade.Target.Match(p.Kind, pi.Base(), conf.Environment(), p.SitesMatrix) {
   317				continue
   318			}
   319	
   320			for ck, cv := range cascade.Fields {
   321				if done := p.setCascadeEarlyValueIfNotSet(ck, cv); done {
   322					break
   323				}
   324			}
   325	
   326		}
   327	
   328		if sitesMatrixBaseOnly {
   329			p.SitesMatrix = sitesmatrix.VectorIteratorToStore(sitesMatrixBase)
   330		} else {
   331			p.SitesMatrix = buildSitesMatrixFromSitesConfig(
   332				conf,
   333				sitesMatrixBase,
   334				p.Sites,
   335			)
   336		}
   337	
   338		// Finally apply the cascades with site filtering.
   339		// These may also contain site specific settings,
   340		// so preserve the original matrix for comparison.
   341		sitesMatrixBefore := p.Sites.Matrix
   342		var hadCascadeMatch bool
   343	
   344		for cascade := range cascades.All() {
   345			if cascade.Target.SitesMatrixCompiled == nil {
   346				continue
   347			}
   348	
   349			if !cascade.Target.Match(p.Kind, pi.Base(), conf.Environment(), p.SitesMatrix) {
   350				continue
   351			}
   352	
   353			hadCascadeMatch = true
   354	
   355			for ck, cv := range cascade.Fields {
   356				if done := p.setCascadeEarlyValueIfNotSet(ck, cv); done {
   357					break
   358				}
   359			}
   360	
   361		}
   362	
   363		if hadCascadeMatch && !sitesMatrixBaseOnly && !sitesMatrixBefore.Equal(p.Sites.Matrix) {
   364			// Matrix has changed, rebuild.
   365			p.SitesMatrix = buildSitesMatrixFromSitesConfig(
   366				conf,
   367				sitesMatrixBase,
   368				p.Sites,
   369			)
   370		}
