func (fs *componentFs) applyFilenameSitesMatrix(meta *FileMeta) {
	pi := meta.PathInfo
	pp := fs.opts.Cfg.PathParser()
	configuredDimensions := fs.opts.Cfg.ConfiguredDimensions()
	b := sitesmatrix.NewIntSetsBuilder(configuredDimensions)

	var found, foundLang, nonDefaultLang bool
	langs := pi.Langs()
	if len(langs) == 0 {
		if lang := pi.Lang(); lang != "" {
			langs = []string{lang}
		}
	}
	for _, lang := range langs {
		if idx, ok := pp.LanguageIndex[lang]; ok {
			b.WithLanguageIndices(idx)
			found = true
			foundLang = true
			nonDefaultLang = nonDefaultLang || idx > 0
		}
	}
	for _, version := range pi.Versions() {
		if idx := configuredDimensions.ConfiguredVersions.ResolveIndex(version); idx >= 0 {
			b.WithVersionIndices(idx)
			found = true
		}
	}
	for _, role := range pi.Roles() {
		if idx := configuredDimensions.ConfiguredRoles.ResolveIndex(role); idx >= 0 {
			b.WithRoleIndices(idx)
			found = true
		}
	}

	if !found {
		return
	}

	b.WithDimensionsFromOtherIfNotSet(meta.SitesMatrix)
	switch meta.Component {
	case files.ComponentFolderContent:
		b.WithDefaultsIfNotSet()
	case files.ComponentFolderLayouts:
		b.WithAllIfNotSet()
	case files.ComponentFolderStatic:
		b.WithDefaultsAndAllLanguagesIfNotSet()
	}

	meta.SitesMatrix = b.Build()
	if foundLang {
		// Give priority to myfile.sv.txt inside the sv filesystem.
		meta.Weight++
		if nonDefaultLang {
			meta.SitesMatrix = sitesmatrix.NewWeightedVectorStore(meta.SitesMatrix, 10)
		}
	}
}

